  'db7cba5e-bf0a-42fa-9c26-4067bd501b3a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus and the Three Pillars — Why Metrics Alone Won't Save Your On-Call$escape$,
  $escape$Prometheus dominates the metrics pillar — scraping /metrics endpoints every 15s, storing time-series, letting you alert on rate(http_requests_total{status="5xx"}[5m]) > 0.01. But metrics only answer what broke and when. Without the other two pillars, you're flying blind on why and where.

Traces fill the where: a p99 latency spike in histogram_quantile(0.99, rate(http_request_duration_seconds_bucket[5m])) tells you nothing about which service leg is slow. Prometheus exemplars bridge this gap — histograms and counters can embed {traceID="abc123"} labels directly in the scrape payload, letting Grafana jump from a metric spike straight to the offending Tempo trace without a separate lookup.

Logs fill the why: Loki's LogQL mirrors PromQL syntax, so you can correlate a firing rate() alert with {app="api"} |= "panic" in the same time window. Grafana's Explore view lets you pivot across all three signals without losing context.

Without traces, you chase symptoms. Without logs, you guess causes. Prometheus alone is a dashboard; all three together are a debugger.$escape$,
  $escape$httpReqs := prometheus.NewHistogramVec(
    prometheus.HistogramOpts{
        Name:    "http_request_duration_seconds",
        Buckets: prometheus.DefBuckets,
    },
    []string{"method", "status"},
)

// Attach trace ID as exemplar — links metric spike → Tempo trace
obs := httpReqs.With(prometheus.Labels{"method": r.Method, "status": statusStr})
if ea, ok := obs.(prometheus.ExemplarObserver); ok {
    ea.ObserveWithExemplar(duration.Seconds(), prometheus.Labels{
        "traceID": span.SpanContext().TraceID().String(),
    })
}$escape$,
  $escape$go$escape$,
