INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9abaf1fb-d7d4-4d42-9dc2-76eb1cc79c86',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus + Grafana — Variable Templating That Actually Scales$escape$,
  $escape$Grafana's variable templating becomes powerful when driven directly by Prometheus label values. Use `label_values(up{job=~"$job"}, instance)` as a query variable's data source query — this auto-populates an instance dropdown from your live scrape targets, staying in sync without manual maintenance.

For multi-select variables, enable 'Include All Option' and set the custom all-value to `.+` so it renders as a valid PromQL regex. Then reference it in panels as `instance=~"$instance"` — the tilde is mandatory for regex matching.

Chain variables by referencing earlier ones: define `$job` first, then use it inside the `$instance` label_values query. Grafana resolves dependencies in order, so drilling from job → instance → pod works without extra configuration.

For alerting, wire Prometheus Alertmanager as a data source alongside your Prometheus server. Use Grafana's unified alerting with `$__interval` in your alert queries — e.g., `rate(http_requests_total[${__interval}])` — so the evaluation window adapts to the panel's time range. Set `Min interval` to match your `scrape_interval` (typically 15s or 30s) to avoid sub-scrape-interval gaps in alert evaluation.$escape$,
  $escape$// Variable: $job
label_values(up, job)

// Variable: $instance (chained from $job)
label_values(up{job=~"$job"}, instance)

// Panel query using multi-select variables
sum by (handler) (
  rate(http_request_duration_seconds_count{
    job=~"$job",
    instance=~"$instance"
  }[$__rate_interval])
)

// Alert query — uses $__interval for adaptive evaluation
rate(http_requests_total{job=~"$job", status=~"5.."}[$__rate_interval])
  /
rate(http_requests_total{job=~"$job"}[$__rate_interval]) > 0.05$escape$,
  $escape$bash$escape$,
