INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '61cccc6a-b07b-42da-89a7-89e2230e559b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus + OpenTelemetry — Vendor-Neutral Instrumentation Without Losing Your Scrape Configs$escape$,
  $escape$OpenTelemetry's Prometheus exporter bridges both ecosystems without a Collector middleman: it exposes a `/metrics` endpoint your existing scrape configs hit directly. The `go.opentelemetry.io/otel/exporters/prometheus` package wraps a `prometheus.Registry` under the hood, translating OTel instruments into Prometheus metric families — `Int64Counter` → counter, `Float64Histogram` → histogram with configurable explicit buckets.

The portability payoff: swap `prometheus.New()` for an OTLP exporter targeting a Collector, and your instrumentation code is untouched. The Collector's `prometheusremotewrite` exporter pushes to any `remote_write`-compatible backend — Thanos, Cortex, Mimir — while the `prometheus` receiver scrapes existing Prometheus endpoints and re-exports as OTLP.

For Collector pipelines, set `receive_min_time: 0s` on the `prometheus` receiver to prevent staleness gaps between scrape intervals. Cardinality is the sharpest risk: every OTel attribute becomes a Prometheus label. Apply a `transform` processor early in the pipeline to drop high-cardinality attributes before they inflate TSDB chunk count and bloat WAL replay time.$escape$,
  $escape$exporter, _ := prometheus.New()
provider := metric.NewMeterProvider(metric.WithReader(exporter))
otel.SetMeterProvider(provider)

meter := provider.Meter("myapp/http")
reqCounter, _ := meter.Int64Counter(
    "http_requests_total",
    metric.WithDescription("Total HTTP requests handled"),
)

// Inside your HTTP handler:
reqCounter.Add(ctx, 1,
    attribute.String("method", r.Method),
    attribute.Int("status", statusCode),
)
// Serve with: promhttp.Handler()$escape$,
  $escape$go$escape$,
