INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6dc88960-407b-4b5c-a2cb-850ce7c4c8b9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus Exemplars — Bridging Metrics and Distributed Traces$escape$,
  $escape$Prometheus doesn't trace natively — but its exemplar feature bridges metrics and distributed traces without a sidecar. Exemplars attach structured labels (like traceID) directly to histogram and counter observations, letting Grafana jump from a latency spike to the exact Tempo or Jaeger trace that caused it.

Enable exemplar storage at startup with --enable-feature=exemplar-storage. In Go instrumentation, extract the trace ID from the OTel span context and push it via ObserveWithExemplar. Prometheus stores up to 100 exemplars per series by default; tune with --storage.exemplar.exemplars-per-series.

Sampling strategy matters here: exemplars only carry signal when your tracer actually samples the request. Align your head-based sampler ratio with your scrape interval — a TraceIdRatioBased(0.1) sampler at a 15s scrape interval means roughly 1-in-10 requests will have a trace link attached to their metric observation. Misalign these and your exemplars will be sparse or misleading.

Query them via /api/v1/query_exemplars?query=http_request_duration_seconds&start=...&end=... — Grafana renders exemplars as diamonds on time-series panels, each clickable through to your trace backend.$escape$,
  $escape$var requestDuration = prometheus.NewHistogramVec(prometheus.HistogramOpts{
    Name:    "http_request_duration_seconds",
    Help:    "HTTP request latency with trace exemplars.",
    Buckets: prometheus.DefBuckets,
}, []string{"route"})

func recordWithExemplar(ctx context.Context, route string, d float64) {
    span := trace.SpanFromContext(ctx)
    obs := requestDuration.With(prometheus.Labels{"route": route})
    if eo, ok := obs.(prometheus.ExemplarObserver); ok {
        eo.ObserveWithExemplar(d, prometheus.Labels{
            "traceID": span.SpanContext().TraceID().String(),
        })
        return
    }
    obs.Observe(d)
}$escape$,
  $escape$go$escape$,
