INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3bfee498-153a-4914-b8a3-91167c6e9351',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus + Sentry — Filling the Gaps Below Your Scrape Boundary$escape$,
  $escape$Prometheus gives you RED metrics at the scrape boundary — error rates via `rate(http_requests_total{status=~"5.."}[5m])`, latency via histogram quantiles. But it can't capture the exception stacktrace, resolve a minified JS callsite, or tell you what a user was clicking when the 500 fired.

Sentry fills those gaps orthogonally.

**Error capture** hooks into unhandled exceptions and manual `sentry_sdk.capture_exception()` calls. Tag events with the same label dimensions you use in PromQL (`job`, `instance`, `env`) — so when Alertmanager fires on a 500-rate spike, you can jump straight to correlated Sentry issue groups without pivoting tools.

**Source maps** de-obfuscate minified JS stack traces. Upload via `sentry-cli releases files <release> upload-sourcemaps ./dist` at CI time, or use the Sentry Vite/webpack plugin for automatic injection.

**Performance monitoring** creates distributed traces with spans — no cardinality ceiling unlike Prometheus histogram buckets. Each `start_transaction()` captures wall-clock duration, DB query time, and external HTTP latency at the individual request level, not the aggregate.

**Session replay** records DOM mutations and network waterfall for error-adjacent sessions — the "why did this 500 happen from the user's perspective" that no PromQL expression can answer.$escape$,
  $escape$import sentry_sdk
from sentry_sdk import start_transaction, set_tag

sentry_sdk.init(
    dsn="https://<key>@sentry.io/<project>",
    traces_sample_rate=0.1,  # sample 10% — deliberate, like Prometheus scrape interval tradeoffs
    release="api@2.3.1",
    environment="production",
)

# Mirror your Prometheus label taxonomy so Alertmanager alerts correlate to Sentry issues
set_tag("job", "payments-service")
set_tag("instance", "pod-7f9b")

# Individual trace — no histogram bucket config, no cardinality risk
with start_transaction(op="http.server", name="POST /checkout") as txn:
    txn.set_tag("payment_method", "stripe")
    process_payment()  # spans, DB queries, and errors captured automatically$escape$,
  $escape$python$escape$,
