INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5c293a81-636c-4803-b56d-9778f47409b9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus vs Datadog — APM, Logs, Synthetics, and the Unified Platform Trade-off$escape$,
  $escape$Prometheus users evaluating Datadog face a familiar dilemma: your current stack likely stitches together Prometheus + Loki + Tempo + Grafana for the same unified view Datadog ships out of the box. The trade-off is real.

**APM:** Datadog auto-instruments services and correlates traces with metrics natively. With Prometheus, you wire OpenTelemetry → Tempo for traces and query them alongside PromQL dashboards manually — possible, but three config files instead of one agent install.

**Logs:** Datadog Logs indexes everything with faceted search. Prometheus users reach for Loki, which shines when log labels mirror your existing `job`/`instance` label taxonomy — but LogQL is another DSL to maintain on top of PromQL.

**Synthetics:** Datadog Synthetics provides browser + API checks with global PoPs. The Prometheus equivalent is `blackbox_exporter` — scraping probe endpoints and alerting on `probe_success == 0`. No global PoPs, but zero vendor lock-in.

**Cost reality:** Datadog bills per host plus custom metric cardinality. If you're already tracking 500+ label combinations via `relabel_configs`, your Datadog bill will be non-trivial. Prometheus's pull model scales with your own infra, not tag explosion.$escape$,
  $escape$# Test blackbox_exporter probe (Prometheus Synthetics equivalent)
curl -s "http://blackbox-exporter:9115/probe?target=https://api.example.com/health&module=http_2xx" \
  | grep -E "^probe_(success|duration_seconds|http_status_code)"

# Expected output:
# probe_duration_seconds 0.134
# probe_http_status_code 200
# probe_success 1

# Equivalent Datadog Synthetic alert — in Prometheus:
# ALERT SyntheticCheckDown
#   IF probe_success{job="blackbox_http"} == 0
#   FOR 2m
#   LABELS { severity="critical" }$escape$,
  $escape$bash$escape$,
