INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'caeaea7e-d62c-4f1c-b676-25102b887c98',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus SLIs, SLOs & Error Budgets — Defining What Good Looks Like in PromQL$escape$,
  $escape$An SLI is a PromQL expression measuring user-facing behavior. The canonical availability SLI for a request-based service: `rate(http_requests_total{status=~"5.."}[5m]) / rate(http_requests_total[5m])`. Your SLO is the threshold — say 99.9% — and your error budget is the tolerable failure slice: 0.1% of requests over a 30-day window.

Don't alert on instantaneous SLI breaches. Use burn-rate alerts instead. A burn rate of 14.4× over 1 hour means your entire monthly budget is gone in 2 hours — that's the Google SRE page-worthy threshold. Prometheus recording rules are essential here: pre-compute error ratios on a short interval so Alertmanager queries stay cheap. Track total budget consumed with `increase(http_requests_total{status=~"5.."}[30d]) / (0.001 * increase(http_requests_total[30d]))` — when this ratio exceeds 1, the SLO window is broken. SLAs are contractual wrappers around SLOs with financial consequences; keep your internal SLO tighter than your SLA to preserve a safety margin.$escape$,
  $escape$groups:
  - name: slo.rules
    interval: 30s
    rules:
      - record: job:error_budget_burn:rate1h
        expr: |
          rate(http_requests_total{status=~"5.."}[1h])
          / rate(http_requests_total[1h])
          / 0.001  # 1 - 0.999 SLO target
  - name: slo.alerts
    rules:
      - alert: HighErrorBudgetBurn
        expr: job:error_budget_burn:rate1h > 14.4
        for: 2m
        labels:
          severity: critical
        annotations:
          summary: "Burning at {{ $value }}x — budget exhausted in {{ printf \"%.1f\" (720 | $value) }}h"$escape$,
  $escape$bash$escape$,
