INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8adcb9ef-e66b-46f2-884f-697a958d3eb9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus Cardinality Cost — High-Series Metrics and the Sampling Trade-Off$escape$,
  $escape$Every unique label combination in Prometheus creates a distinct time series stored in TSDB. A counter like `http_requests_total{method, status, path}` is manageable — but add a `user_id` label and you're potentially generating millions of series. TSDB's head block keeps active series in RAM; at ~1–2 KB per series, 10M series consumes 10–20 GB of memory before a single byte hits disk.

Diagnose cardinality with `prometheus_tsdb_head_series` and `topk(10, count by (__name__)({__name__=~".+"}))`. Eliminate offenders using `metric_relabel_configs` with `labeldrop` or regex replacement before ingestion — not after, because scraping has already paid the cost.

For trace sampling, Prometheus doesn't do head-based sampling natively, but Exemplars (enabled via `--enable-feature=exemplar-storage`) let you attach sparse trace IDs directly to histogram observations. Each metric holds a configurable ring buffer (`--storage.exemplar.records-to-store=100000`) — high signal, near-zero cardinality cost.

The sharpest lever is pre-aggregation via recording rules: collapse high-cardinality `path` labels into normalized patterns before storage. You lose per-path drill-down but cut series count by orders of magnitude — a deliberate, measurable trade-off.$escape$,
  $escape$# prometheus.yml
scrape_configs:
  - job_name: 'api'
    static_configs:
      - targets: ['localhost:8080']
    metric_relabel_configs:
      # Drop high-cardinality label before TSDB ingestion
      - action: labeldrop
        regex: user_id
      # Normalize noisy path segments
      - source_labels: [path]
        regex: '/api/v1/users/[^/]+'
        target_label: path
        replacement: '/api/v1/users/:id'
        action: replace

# recording_rules.yml — pre-aggregate before storage
groups:
  - name: api_cost_reduction
    rules:
      - record: job:http_requests_total:rate5m
        expr: sum by (job, status) (rate(http_requests_total[5m]))$escape$,
  $escape$bash$escape$,
