INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0635e389-e741-4489-b25a-a8165a9984ce',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus Synthetic Monitoring — Uptime Checks, Multi-Step API Tests, and SLA Alerting$escape$,
  $escape$Prometheus doesn't natively run synthetic checks, but the Blackbox Exporter turns it into a powerful uptime engine. Deploy blackbox_exporter and configure probe modules — `http_2xx` for simple uptime, or custom modules with `fail_if_body_not_matches_regexp` for content validation. Scrape targets via relabeling in `prometheus.yml` using the `params` and `metrics_path: /probe` pattern so each endpoint becomes a labeled time series.

For multi-step API flows, chain probes using Prometheus recording rules that compute derived signals — e.g., `probe_success{job="checkout-flow"} == 1` across three sequential endpoint probes. Wire these into an alerting rule with `for: 5m` to avoid flapping on transient failures.

SLA alerting uses multi-window, multi-burn-rate rules (the Google SRE model). Define a `probe_success` error budget: if your SLA is 99.9%, your 30-day error budget is ~43 minutes. Alert when `1 - avg_over_time(probe_success[1h]) > 14.4 * (1 - 0.999)` (fast burn) to page on-call before budget exhausts. Pair with `probe_duration_seconds` percentiles to catch latency SLA breaches separately from availability.$escape$,
  $escape$# prometheus.yml — blackbox multi-target probe via relabeling
scrape_configs:
  - job_name: 'blackbox-http'
    metrics_path: /probe
    params:
      module: [http_2xx]
    static_configs:
      - targets:
          - https://api.example.com/health
          - https://api.example.com/checkout
    relabel_configs:
      - source_labels: [__address__]
        target_label: __param_target
      - source_labels: [__param_target]
        target_label: instance
      - target_label: __address__
        replacement: blackbox-exporter:9115

# alerting rule — multi-burn-rate SLA alert (99.9% target)
groups:
  - name: sla.rules
    rules:
      - alert: HighErrorBurnRate
        expr: |
          (1 - avg_over_time(probe_success{job="blackbox-http"}[1h])) > 14.4 * 0.001
        for: 2m
        labels:
          severity: page
        annotations:
          summary: "Fast burn on {{ $labels.instance }} — SLA at risk"$escape$,
  $escape$bash$escape$,
