INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '108227e5-69b9-49c7-81b2-9ad6b8d0fb0e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus Health Checks — Liveness, Readiness, and Dependency Probes Done Right$escape$,
  $escape$Prometheus doesn't have built-in liveness/readiness concepts — those live in Kubernetes — but you control what those probes check, and that's where Prometheus shines. Expose a `/metrics` endpoint and instrument your own health signal using `prometheus_client`.

For liveness, a simple `Gauge` set to `1` when the app is running (and `0` on fatal error) gives you a scrapeable signal. For readiness, gate on dependency health: check your DB connection, Redis ping, and downstream APIs, then set a labeled gauge per dependency. Prometheus then lets you alert on `dependency_up{name="postgres"} == 0` with a short `for: 30s` window.

For uptime monitoring, use `process_start_time_seconds` (exposed automatically by most client libraries) combined with `time() - process_start_time_seconds` to derive uptime in recording rules. Track SLA compliance with `avg_over_time(app_ready[24h])` — if it dips below 0.999, you're under three-nines. Pair with `up` (the scrape health metric) to distinguish app-reported unreadiness from total scrape failure.$escape$,
  $escape$from prometheus_client import Gauge, start_http_server
import psycopg2, time

app_live = Gauge('app_liveness', 'App is alive')
app_ready = Gauge('app_readiness', 'App is ready to serve traffic')
dep_up = Gauge('dependency_up', 'Dependency health', ['name'])

def check_dependencies():
    try:
        conn = psycopg2.connect("postgresql://localhost/mydb", connect_timeout=2)
        conn.close()
        dep_up.labels(name='postgres').set(1)
    except Exception:
        dep_up.labels(name='postgres').set(0)

def health_loop():
    app_live.set(1)
    while True:
        check_dependencies()
        ready = dep_up.labels(name='postgres')._value.get() == 1.0
        app_ready.set(1 if ready else 0)
        time.sleep(15)

start_http_server(8000)
health_loop()$escape$,
  $escape$python$escape$,
