INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e92da710-a144-416c-9936-7357fbaedda5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Prometheus+Grafana vs Datadog vs New Relic — A Cardinality-First Decision Framework$escape$,
  $escape$Prometheus+Grafana wins when you need full PromQL control, custom recording rules, and zero per-metric costs. If your active series stay under ~10M and you have SRE bandwidth for Alertmanager config and retention tuning, self-hosted is the right call. Query your current cardinality with `count({__name__=~".+"})` before committing — that single number drives most of the decision.

Datadog becomes rational when APM traces need to correlate with metrics out-of-the-box, or when your org is polyglot and can't standardize on a scrape model. The tipping point is usually 500+ hosts — at $23/host plus custom metric charges (first 100 free, then per-metric billing), costs compound fast. The escape hatch: keep Prometheus as the collection layer and `remote_write` to Datadog, paying only for what matters.

New Relic's NRDB is compelling for 13-month retention with NRQL and it natively accepts `remote_write` — migration is a config swap, not a rewrite.

Rule of thumb: cardinality under control + SRE capacity = Prometheus+Grafana. Unified traces-logs-metrics with minimal ops overhead = go managed.$escape$,
  $escape$# Baseline cardinality before choosing self-hosted Prometheus
curl -s 'http://localhost:9090/api/v1/query' \
  --data-urlencode 'query=count({__name__=~".+"})' \
  | jq '.data.result[0].value[1]'

# Top 10 metrics driving cardinality — prune before scaling
curl -s 'http://localhost:9090/api/v1/query' \
  --data-urlencode 'query=topk(10, count by (__name__)({__name__=~".+"}))' \
  | jq '.data.result[] | {metric: .metric.__name__, series: .value[1]}'$escape$,
  $escape$bash$escape$,
